import classes from "./DirectMessageItem.module.css";

const DirectMessageItem = () => {
  return (
    <li className={classes["item-wrapper"]}>
      <div className={classes["link-button"]}>
        <a className={classes["link"]} href="/">
          <div className={classes["content-layout"]}>
            <div className={classes["avatar"]}>
              <svg
                className={classes["button-icon"]}
                xmlns="http://www.w3.org/2000/svg"
                viewBox="0 0 448 512"
                height="16"
                width="16"
              >
                <path
                  d="M0.5,0 L0.5,1.5 C0.5,5.65 2.71,9.28 6,11.3 L6,16 L21,16 L21,14 C21,11.34 15.67,10 13,10 C13,10 12.83,10 12.75,10 C8,10 4,6 4,1.5 L4,0 L0.5,0 Z M13,0 C10.790861,0 9,1.790861 9,4 C9,6.209139 10.790861,8 13,8 C15.209139,8 17,6.209139 17,4 C17,1.790861 15.209139,0 13,0 Z"
      
                ></path>
              </svg>
            </div>
            <div className={classes["text"]}>Erric</div>
          </div>
        </a>
      </div>
    </li>
  );
};

export default DirectMessageItem;
